import{_ as o,c as s,o as n,a4 as a}from"./chunks/framework.HaEZziQ1.js";const e="/FrontEndLearnNotes/assets/gwxz1.0dXOUORK.jpg",p="/FrontEndLearnNotes/assets/xzbbhptxz.C4gIo1i0.jpg",l="/FrontEndLearnNotes/assets/az1.OKq7UrpB.jpg",r="/FrontEndLearnNotes/assets/azml.B7J6JKwu.jpg",t="/FrontEndLearnNotes/assets/qd.hDmJLTSS.jpg",c="/FrontEndLearnNotes/assets/qdcg.BJAMK5o8.jpg",d="/FrontEndLearnNotes/assets/pzyx.C-lp5mm6.jpg",i="/FrontEndLearnNotes/assets/win11-xtbl.DgmBzVqL.jpg",m="/FrontEndLearnNotes/assets/xtbl-bj.DilCxzNv.jpg",g="/FrontEndLearnNotes/assets/tj-hjbl.Ck2jtl1G.jpg",b="/FrontEndLearnNotes/assets/Compass-lj.BPPMMju8.jpg",h="/FrontEndLearnNotes/assets/Compass-ljcg.BMhw75WW.jpg",u="/FrontEndLearnNotes/assets/1585482451810.CzxTvK9m.png",_="/FrontEndLearnNotes/assets/1585482549628.VldOwjGN.png",y="/FrontEndLearnNotes/assets/1585482465701.D1CB22CW.png",C="/FrontEndLearnNotes/assets/1585482566526.BwyDMeE4.png",B="/FrontEndLearnNotes/assets/1585482668249.BSaE7sLX.png",D="/FrontEndLearnNotes/assets/VSCode-plugins.CYjg1Oh2.jpg",f="/FrontEndLearnNotes/assets/VSCode-plugins-lianjie.CsyusFfj.jpg",P=JSON.parse('{"title":"mongoDB下载安装和配置","description":"","frontmatter":{},"headers":[],"relativePath":"Document/数据库的使用/MongoDB数据库/MongoDB下载安装和配置.md","filePath":"Document/数据库的使用/MongoDB数据库/MongoDB下载安装和配置.md","lastUpdated":1709668918000}'),F={name:"Document/数据库的使用/MongoDB数据库/MongoDB下载安装和配置.md"},M=a('<h1 id="mongodb下载安装和配置" tabindex="-1">mongoDB下载安装和配置 <a class="header-anchor" href="#mongodb下载安装和配置" aria-label="Permalink to &quot;mongoDB下载安装和配置&quot;">​</a></h1><h2 id="mongodb安装和启动运行配置" tabindex="-1">mongoDB安装和启动运行配置 <a class="header-anchor" href="#mongodb安装和启动运行配置" aria-label="Permalink to &quot;mongoDB安装和启动运行配置&quot;">​</a></h2><p>安装文档：<a href="https://www.mongodb.com/docs/manual/administration/install-community/" target="_blank" rel="noreferrer">Install MongoDB Community Edition — MongoDB Manual</a></p><h2 id="_1-下载" tabindex="-1">1.下载 <a class="header-anchor" href="#_1-下载" aria-label="Permalink to &quot;1.下载&quot;">​</a></h2><p>1.打开官网：<a href="https://www.mongodb.com/" target="_blank" rel="noreferrer">https://www.mongodb.com/</a></p><p>2.点击社区版：选择 <code>Products &gt; Community Edition</code> 就能进入社区版</p><p><img src="'+e+'" alt="gwxz1.jpg"></p><p>3.选择版本下载：</p><p><img src="'+p+'" alt="xzbbhptxz.jpg"></p><hr><h2 id="_2-安装、配置与启动" tabindex="-1">2.安装、配置与启动 <a class="header-anchor" href="#_2-安装、配置与启动" aria-label="Permalink to &quot;2.安装、配置与启动&quot;">​</a></h2><p>1.安装：到这一步：complete（完整的安装：默认安装到系统盘）| Custom（习惯安装：可以自定义安装路径）。然后一路next</p><p><img src="'+l+'" alt="az1.jpg"></p><p>最后 点击“finish”按钮完成安装</p><p>2.安装完成之后找到对应的安装目录</p><p><img src="'+r+'" alt="azml.jpg"></p><p>3.在安装路径下-&gt;创建<code>data\\db</code>(存储 MongoDB 产生的数据)，和 <code>data\\log</code> 日志文件夹</p><p>4.运行MongoDB服务</p><p>进入 <code>bin</code> 目录下，<code>cmd</code> 进入 <code>命令行窗口</code>，使用命令的指定存储数据文件的形式启动：<code>mongod --dbpath=..\\data\\db</code></p><p>从 MongoDB 目录的 bin 目录中执行 mongod.exe 文件。 C:\\mongodb\\bin&gt;mongod --dbpath D:\\mongo\\data\\db</p><p><img src="'+t+`" alt="qd.jpg"></p><p>4.1.服务相关命令：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">启动服务：net</span><span style="color:#98C379;"> start</span><span style="color:#98C379;"> MongoDB</span></span>
<span class="line"><span style="color:#61AFEF;">关闭服务：net</span><span style="color:#98C379;"> stop</span><span style="color:#98C379;"> MongoDB</span></span>
<span class="line"><span style="color:#61AFEF;">移除服务：目录路径\\MongoDB\\bin\\mongod.exe</span><span style="color:#98C379;"> –remove</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>5.本地测试启动地址：localhost:27017</p><p>成功启动：看到 <code>It looks like you are trying to access MongoDB over HTTP on the native driver port.</code> 就能证明 MongoDB 启动成功</p><p><img src="`+c+`" alt="qdcg.jpg"></p><p>6.存放数据和日志目录：安装目录下新建<code>conf\\mongodb.conf</code>文件，给该文件添加些配置信息：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">systemLog:</span></span>
<span class="line"><span style="color:#61AFEF;">  destination:</span><span style="color:#98C379;"> file</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  # 指定日志存放文件</span></span>
<span class="line"><span style="color:#61AFEF;">  path:</span><span style="color:#98C379;"> C:</span><span style="color:#56B6C2;">\\P</span><span style="color:#98C379;">rogram</span><span style="color:#98C379;"> Files</span><span style="color:#56B6C2;">\\M</span><span style="color:#98C379;">ongoDB</span><span style="color:#56B6C2;">\\S</span><span style="color:#98C379;">erver</span><span style="color:#56B6C2;">\\6</span><span style="color:#98C379;">.0</span><span style="color:#56B6C2;">\\l</span><span style="color:#98C379;">og</span><span style="color:#56B6C2;">\\m</span><span style="color:#98C379;">ongodb.log</span></span>
<span class="line"><span style="color:#61AFEF;">  logAppend:</span><span style="color:#D19A66;"> true</span></span>
<span class="line"><span style="color:#61AFEF;">storage:</span></span>
<span class="line"><span style="color:#61AFEF;">  journal:</span></span>
<span class="line"><span style="color:#61AFEF;">    enabled:</span><span style="color:#D19A66;"> true</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  # 指定存放数据文件的全路径</span></span>
<span class="line"><span style="color:#61AFEF;">  dbPath:</span><span style="color:#98C379;"> C:</span><span style="color:#56B6C2;">\\P</span><span style="color:#98C379;">rogram</span><span style="color:#98C379;"> Files</span><span style="color:#56B6C2;">\\M</span><span style="color:#98C379;">ongoDB</span><span style="color:#56B6C2;">\\S</span><span style="color:#98C379;">erver</span><span style="color:#56B6C2;">\\6</span><span style="color:#98C379;">.0</span><span style="color:#56B6C2;">\\d</span><span style="color:#98C379;">ata</span></span>
<span class="line"><span style="color:#61AFEF;">net:</span></span>
<span class="line"><span style="color:#61AFEF;">  bindIp:</span><span style="color:#D19A66;"> 127.0</span><span style="color:#98C379;">.0.1</span></span>
<span class="line"><span style="color:#61AFEF;">  port:</span><span style="color:#D19A66;"> 27020</span></span>
<span class="line"><span style="color:#61AFEF;">setParameter:</span></span>
<span class="line"><span style="color:#61AFEF;">  enableLocalhostAuthBypass:</span><span style="color:#D19A66;"> false</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p>详细配置可参考：<a href="https://www.mongodb.com/docs/manual/reference/configuration-options/" target="_blank" rel="noreferrer">官方文档</a></p><p>6.1 进入 <code>bin</code> 目录下，<code>cmd</code> 进入 <code>命令行窗口</code>，使用命令的形式让 <code>mongodb</code> 指定配置文件启动：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">mongod</span><span style="color:#D19A66;"> -f</span><span style="color:#98C379;"> ..</span><span style="color:#56B6C2;">\\c</span><span style="color:#98C379;">onf</span><span style="color:#56B6C2;">\\m</span><span style="color:#98C379;">ongodb.conf</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 或者</span></span>
<span class="line"><span style="color:#61AFEF;">mongod</span><span style="color:#D19A66;"> --config</span><span style="color:#98C379;"> ..</span><span style="color:#56B6C2;">\\c</span><span style="color:#98C379;">onf</span><span style="color:#56B6C2;">\\m</span><span style="color:#98C379;">ongodb.conf</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><img src="`+d+'" alt="pzyx.jpg"></p><hr><h2 id="_3-mongodb连接操作和相关命令" tabindex="-1">3.MongoDB连接操作和相关命令 <a class="header-anchor" href="#_3-mongodb连接操作和相关命令" aria-label="Permalink to &quot;3.MongoDB连接操作和相关命令&quot;">​</a></h2><h3 id="_1-shell-命令连接" tabindex="-1">1.Shell 命令连接 <a class="header-anchor" href="#_1-shell-命令连接" aria-label="Permalink to &quot;1.Shell 命令连接&quot;">​</a></h3><p>如果使用 Shell 命令的形式打开 MongoDB，最好先配置以下环境变量，打开</p><p>鼠标右键 <code>我的电脑（此电脑）</code> - <code>属性</code> - <code>高级系统设置</code> 再选择 <code>环境变量</code></p><p><img src="'+i+'" alt="win11-xtbl.jpg"></p><p>选择 <code>Path</code>，点击 <code>编辑</code></p><p><img src="'+m+'" alt="xtbl-bj.jpg"> 点击 <code>新建</code> ，然后把 MongoDB 的 <code>bin</code> 目录路径粘贴上去：比如我的 <code>C:\\Program Files\\MongoDB\\Server\\6.0\\bin</code></p><p><img src="'+g+`" alt="tj-hjbl.jpg"></p><p>返回的窗口全部依次点击 <code>确定</code> 即可。</p><h4 id="mongodb相关shell命令文档-后面有空需要学习-install-mongosh-—-mongodb-shell" tabindex="-1">MongoDB相关shell命令文档（后面有空需要学习）：<a href="https://www.mongodb.com/docs/mongodb-shell/install/" target="_blank" rel="noreferrer">Install mongosh — MongoDB Shell</a> <a class="header-anchor" href="#mongodb相关shell命令文档-后面有空需要学习-install-mongosh-—-mongodb-shell" aria-label="Permalink to &quot;MongoDB相关shell命令文档（后面有空需要学习）：[Install mongosh — MongoDB Shell](https://www.mongodb.com/docs/mongodb-shell/install/)&quot;">​</a></h4><p>开启 MongoDB 之后，<code>cmd</code> 进入 <code>命令行窗口</code>，输入命令 ：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">mongo</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 或者</span></span>
<span class="line"><span style="color:#61AFEF;">mongo</span><span style="color:#D19A66;"> --host=127.0.0.1</span><span style="color:#D19A66;"> --port=27017</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>查看已经有的数据库：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">show</span><span style="color:#98C379;"> databases</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>退出 Mongodb</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#56B6C2;">exit</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>查看帮助文档</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">mongo</span><span style="color:#D19A66;"> --help</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="_1-1官方工具mongodb-shell" tabindex="-1">1.1官方工具MongoDB Shell <a class="header-anchor" href="#_1-1官方工具mongodb-shell" aria-label="Permalink to &quot;1.1官方工具MongoDB Shell&quot;">​</a></h4><p>MongoShell是<strong>MongoDB发行版的一个组件</strong>， 安装并启动MongoDB后，将MongoShell连接到正在运行的MongoDB实例，MongoDB手册中的大多数示例使用 MongoShell，然而，许多驱动程序也提供了与MongoDB类似的接口。</p><p><code>MongoDB Shell</code> 官方地址下载：<a href="https://www.mongodb.com/try/download/shell" target="_blank" rel="noreferrer">MongoDB Compass Download | MongoDB</a></p><hr><h4 id="_2-mongodb客户端程序连接" tabindex="-1">2.MongoDB客户端程序连接 <a class="header-anchor" href="#_2-mongodb客户端程序连接" aria-label="Permalink to &quot;2.MongoDB客户端程序连接&quot;">​</a></h4><p>一些连接数据库的图形化工具也能够连接 MongoDB</p><h5 id="_2-1-mongodbcompass-图形化界面客户端" tabindex="-1">2.1. MongoDBCompass-图形化界面客户端 <a class="header-anchor" href="#_2-1-mongodbcompass-图形化界面客户端" aria-label="Permalink to &quot;2.1. MongoDBCompass-图形化界面客户端&quot;">​</a></h5><p><code>Compass</code> 图形化界面客户端：<a href="https://www.mongodb.com/try/download/compass" target="_blank" rel="noreferrer">MongoDB-compass下载</a></p><p>视频地址：<a href="https://www.mongodb.com/presentations/webinar-mongodb-compass-data-navigation-made-easy?utm_campaign=Int_ET_Download%20Center%20-%20Compass%20Download_WW%20-%20Autoresponder%20%28Sept%202017%29&amp;utm_medium=email&amp;utm_source=Eloqua" target="_blank" rel="noreferrer">Webinar: MongoDB Compass - Data navigation made easy | MongoDB</a></p><p>官方总文档地址：<a href="https://www.mongodb.com/docs/" target="_blank" rel="noreferrer">MongoDB Documentation</a></p><p><strong>使用教程文档地址</strong>：<a href="https://www.mongodb.com/docs/compass/current/" target="_blank" rel="noreferrer">What is MongoDB Compass? — MongoDB Compass</a></p><hr><p>下载解压或者安装后：在打开的界面中，输入主机地址、端口等相关信息</p><p><img src="`+b+'" alt="Compass-lj.jpg"></p><p>连接成功：</p><p><img src="'+h+'" alt="Compass-ljcg.jpg"></p><p>图形化界面的好处就是可以很清晰的看到数据库中数据的展示和减少写一些查询语句。</p><hr><h5 id="_2-2-navicat-数据库管理软件" tabindex="-1">2.2. Navicat 数据库管理软件 <a class="header-anchor" href="#_2-2-navicat-数据库管理软件" aria-label="Permalink to &quot;2.2. Navicat 数据库管理软件&quot;">​</a></h5><hr><h5 id="_2-3-robo-3t-客户端管理软件" tabindex="-1">2.3. Robo 3T 客户端管理软件 <a class="header-anchor" href="#_2-3-robo-3t-客户端管理软件" aria-label="Permalink to &quot;2.3. Robo 3T 客户端管理软件&quot;">​</a></h5><p>下载地址：<a href="https://robomongo.org/download" target="_blank" rel="noreferrer">https://robomongo.org/download</a></p><p>安装：傻瓜式安装，全部点击下一步next</p><p>连接和使用：</p><blockquote><p><img src="'+u+'" alt="1585482451810"></p><p><img src="'+_+'" alt="1585482549628"></p><p><img src="'+y+'" alt="1585482465701"></p><p><img src="'+C+'" alt="1585482566526"></p><p><img src="'+B+'" alt="1585482668249"></p></blockquote><hr><h5 id="_2-4-robomongo" tabindex="-1">2.4. Robomongo <a class="header-anchor" href="#_2-4-robomongo" aria-label="Permalink to &quot;2.4. Robomongo&quot;">​</a></h5><hr><h5 id="_2-5-adminmongo" tabindex="-1">2.5 adminMongo <a class="header-anchor" href="#_2-5-adminmongo" aria-label="Permalink to &quot;2.5 adminMongo&quot;">​</a></h5><p>adminMongo管理系统 - WEB/PC端口网页管理：<a href="https://adminmongo.markmoffat.com/" target="_blank" rel="noreferrer">https://adminmongo.markmoffat.com/</a></p><hr><h5 id="_2-6-mongovue-客户端软件" tabindex="-1">2.6 MongoVUE 客户端软件 <a class="header-anchor" href="#_2-6-mongovue-客户端软件" aria-label="Permalink to &quot;2.6 MongoVUE 客户端软件&quot;">​</a></h5><hr><h5 id="_2-7-vs-code连接mongodb数据库" tabindex="-1">2.7 VS Code连接MongoDB数据库 <a class="header-anchor" href="#_2-7-vs-code连接mongodb数据库" aria-label="Permalink to &quot;2.7 VS Code连接MongoDB数据库&quot;">​</a></h5><p>官网文档：<a href="https://www.mongodb.com/docs/mongodb-vscode/" target="_blank" rel="noreferrer">MongoDB for VS Code — MongoDB for VS Code</a></p><p>VS Code搜索安装插件：MongoDB for VS Code</p><p><img src="'+D+'" alt="VSCode-plugins.jpg"></p><p>VS Code 连接：</p><p><img src="'+f+'" alt="VSCode-plugins-lianjie.jpg"></p><p>使用该插件添加数据库：没学会，文档待定</p>',91),w=[M];function v(E,k,j,q,A,x){return n(),s("div",null,w)}const N=o(F,[["render",v]]);export{P as __pageData,N as default};
